INSERT INTO posts ("id", "title", "slug", "excerpt", "image_url", "is_published", "sandbox", "published_at", "user_id", "qa_reviewed", "description", "createdAt", "updatedAt", "seo_title", "content") VALUES (108, E'Guía Completa de la LLC: Qué es, Cómo funciona, Ventajas y Desventajas', E'que-es-llc', E'¿Estás interesado en conocer que es y como funciona una LLC americana? Descubre la guía completa: Definición, Funcionamiento, Ventajas, Problemas y más.', E'https://media.startcompanies.us/blog/que-es-llc/1776354961586-1775755327221-image.png', TRUE, TRUE, E'2026-04-09 16:54:56', 1, FALSE, E'Guía completa de la LLC en USA: qué es, ventajas (responsabilidad limitada, pass-through taxation), desventajas, funcionamiento y comparación con Corp y Sole Proprietorship.', E'2026-04-09 16:54:56', E'2026-04-16 21:56:02', E'Qué es una LLC: Definición, Funcionamiento, Ventajas', '') ON CONFLICT ("id") DO UPDATE SET "title" = EXCLUDED."title", "slug" = EXCLUDED."slug", "excerpt" = EXCLUDED."excerpt", "image_url" = EXCLUDED."image_url", "is_published" = EXCLUDED."is_published", "sandbox" = EXCLUDED."sandbox", "published_at" = EXCLUDED."published_at", "user_id" = EXCLUDED."user_id", "qa_reviewed" = EXCLUDED."qa_reviewed", "description" = EXCLUDED."description", "createdAt" = EXCLUDED."createdAt", "updatedAt" = EXCLUDED."updatedAt", "seo_title" = EXCLUDED."seo_title";
